  ('aviation-f975d768-moex-00073', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '依司法院大法官解釋，關於法律明確性原則，下列敘述何者正確？', '["法律文義應具體詳盡，不得使用不確定法律概念", "法律如使用不確定法律概念，應同時授權訂定命令，以明確詳盡規定其具體內容", "法律使用之不確定法律概念，如主管機關曾作成函釋，即與法律明確性原則無違", "法律雖得使用不確定法律概念，但其文義須非難以理解，且為受規範者所得預見，並可經由司法審 查加以確認"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
  ('aviation-f975d768-moex-00074', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '依現行憲法規定，關於國防事項，下列敘述何者正確？', '["應兼採募兵制", "兵役制度為法律保留事項", "兵役義務非屬憲法保留事項", "兵役制度須考量經濟發展需要"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
  ('aviation-f975d768-moex-00075', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '關於緊急命令與法規命令之異同，下列敘述何者正確？', '["緊急命令發布後10日內提交立法院追認；法規命令亦應即送立法院，未經函送不生效力", "緊急命令與法規命令均不得牴觸法律", "緊急命令依憲法所規定之要件及程序，而法規命令則依行政程序法所定要件及程序為之", "法院對於緊急命令及法規命令均不審查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
  ('aviation-f975d768-moex-00076', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '依刑事訴訟法第93條第2項規定，犯罪嫌疑人遭逮捕後，檢察官認為有羈押之必要，應自逮捕時起24 小時內聲請法院羈押。關於本項規定，下列敘述何者正確？', '["本項規定之內容為絕對法律保留事項，立法者得在符合比例原則之範圍內，將24小時修正為48小時", "本項規定之內容為相對法律保留事項，立法者得授權檢察官在必要時，將24小時延長為48小時", "本項規定之內容為憲法保留事項，立法者不得將24小時修正為48小時", "本項規定之內容為行政保留事項，檢察官得在必要時，將24小時延長為48小時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
  ('aviation-f975d768-moex-00077', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '集會自由應屬表現自由之範疇，依司法院大法官解釋意旨，關於集會自由，下列敘述何者錯誤？', '["集會遊行法對於不遵從解散及制止命令之首謀者科以刑責，將造成寒蟬效應，有違憲法對集會自由 之保障", "國家應提供適當集會場所，採取有效保護集會之安全措施，使參與集會遊行者在毫無恐懼情況下行 使集會自由", "關於集會遊行時間、地點及方式等限制，因無涉集會遊行之目的或內容，屬於立法自由形成範圍", "集會遊行法之事前許可制未排除緊急性及偶發性集會，已違反比例原則之要求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL)
